import React from 'react';
import logo from './logo.svg';
import './App.css';

interface Track {
  name : string;
  artist : string;
  playcount : number;
}

async function fetchTopTracks(username : string, period : string, limit : number) : Promise<Array<Track> | string> {
  const api = 'http://ws.audioscrobbler.com/2.0/?method=user.gettoptracks&user=gfxnx&api_key=c9d3233f3430ee28ba0e643cb973eac5&format=json'

  try {
    const response = await fetch(api);

    if(!response.ok){
      throw new Error(`Error fetching API : ${response.status}`);
    }

    const toptracks = response.json();
    toptracks.track.forEach((track :  Track) => {
      console.log(track);
    });

  } catch (error : any) {
    return (`Error returning API data : ${error.message}`) 
  }
}


